Ty fevent(const double& t, const StackVec<double>& q, const std::vector<double>& args){
    return {q[0], q[1], q[2]*pow(pow(q[2], 2) + pow(q[3], 2), -1./2.), q[3]*pow(pow(q[2], 2) + pow(q[3], 2), -1./2.)};
}

int main(){

    Tt t0 = 0;
    Ty q0 = {-4, -4, pow(2, 0.5)/2, pow(2, 0.5)/2};
    Tt stepsize = 1e-5;
    Tt rtol = 0.;
    Tt atol = 1e-9;
    Tt min_step = 0.;
    std::vector<Tt> args = {1, pow(2, 0.5)/2, pow(2, 0.5)/2, 5./2.};
    Event<Tt, Ty> ev = Event<double, Ty>("checkpoint", nullptr, nullptr, 0.5, 0, fevent, true);

    ODE<Tt, Ty> ode = ODE<Tt, Ty>(ODE_FUNC, t0, q0, stepsize, rtol, atol, min_step, args, "RK45", 0., {ev}, {});

    // ode.integrate(0.49);
    ode.free();
    while (true){
        std::cout << ode.state().t << "    " << ode.state().q << "\n";
        std::cin.get();
        ode.advance();
    }
}